import { FolderOpen, Upload, Play, X, MessageSquare } from "lucide-react";
import { useCallback, useRef, useState } from "react";
import type { RunStatus } from "../types";

interface Props {
  status: RunStatus;
  onStartFolder: (folder: string, prompt?: string) => void;
  onStartFiles: (files: File[], prompt?: string) => void;
  onCancel: () => void;
  onReset: () => void;
}

export function InputPanel({
  status,
  onStartFolder,
  onStartFiles,
  onCancel,
  onReset,
}: Props) {
  const [mode, setMode] = useState<"folder" | "upload">("folder");
  const [folderPath, setFolderPath] = useState("sample_invoices");
  const [files, setFiles] = useState<File[]>([]);
  const [prompt, setPrompt] = useState("");
  const [showPrompt, setShowPrompt] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const isRunning = status === "running" || status === "connecting";
  const isDone = status === "completed" || status === "error";

  const handleSubmit = useCallback(() => {
    const p = prompt.trim() || undefined;
    if (mode === "folder") {
      if (!folderPath.trim()) return;
      onStartFolder(folderPath.trim(), p);
    } else {
      if (files.length === 0) return;
      onStartFiles(files, p);
    }
  }, [mode, folderPath, files, prompt, onStartFolder, onStartFiles]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      setFiles(Array.from(e.target.files));
    }
  };

  const removeFile = (index: number) => {
    setFiles((prev) => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="input-panel">
      <h2>Input</h2>

      <div className="mode-toggle">
        <button
          className={`mode-btn ${mode === "folder" ? "active" : ""}`}
          onClick={() => setMode("folder")}
          disabled={isRunning}
        >
          <FolderOpen size={16} />
          Folder Path
        </button>
        <button
          className={`mode-btn ${mode === "upload" ? "active" : ""}`}
          onClick={() => setMode("upload")}
          disabled={isRunning}
        >
          <Upload size={16} />
          Upload Files
        </button>
      </div>

      {mode === "folder" ? (
        <div className="input-group">
          <label>Server-side folder path</label>
          <input
            type="text"
            value={folderPath}
            onChange={(e) => setFolderPath(e.target.value)}
            placeholder="sample_invoices"
            disabled={isRunning}
          />
        </div>
      ) : (
        <div className="input-group">
          <label>Invoice images (PNG, JPG, TIFF, etc.)</label>
          <div
            className="drop-zone"
            onClick={() => fileInputRef.current?.click()}
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              e.preventDefault();
              if (e.dataTransfer.files) {
                setFiles((prev) => [...prev, ...Array.from(e.dataTransfer.files)]);
              }
            }}
          >
            <Upload size={24} />
            <p>Click or drag files here</p>
            <input
              ref={fileInputRef}
              type="file"
              multiple
              accept="image/*"
              onChange={handleFileChange}
              style={{ display: "none" }}
            />
          </div>
          {files.length > 0 && (
            <ul className="file-list">
              {files.map((f, i) => (
                <li key={i}>
                  <span>{f.name}</span>
                  <button onClick={() => removeFile(i)} className="icon-btn">
                    <X size={14} />
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>
      )}

      <button
        className="prompt-toggle"
        onClick={() => setShowPrompt(!showPrompt)}
      >
        <MessageSquare size={14} />
        {showPrompt ? "Hide" : "Add"} custom prompt
      </button>

      {showPrompt && (
        <div className="input-group">
          <label>Custom instructions (optional)</label>
          <textarea
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            placeholder="e.g. Focus on travel expenses..."
            rows={2}
            disabled={isRunning}
          />
        </div>
      )}

      <div className="action-buttons">
        {isDone ? (
          <button className="btn btn-primary" onClick={onReset}>
            New Run
          </button>
        ) : isRunning ? (
          <button className="btn btn-danger" onClick={onCancel}>
            Cancel
          </button>
        ) : (
          <button
            className="btn btn-primary"
            onClick={handleSubmit}
            disabled={mode === "folder" ? !folderPath.trim() : files.length === 0}
          >
            <Play size={16} />
            Process Invoices
          </button>
        )}
      </div>
    </div>
  );
}

