import { Check, Circle, Loader, AlertCircle } from "lucide-react";
import type { ProgressStep } from "../types";

interface Props {
  steps: ProgressStep[];
}

const STATUS_ICON = {
  pending: <Circle size={16} className="step-icon pending" />,
  running: <Loader size={16} className="step-icon running spin" />,
  completed: <Check size={16} className="step-icon completed" />,
  error: <AlertCircle size={16} className="step-icon error" />,
};

export function PipelineProgress({ steps }: Props) {
  const completedCount = steps.filter((s) => s.status === "completed").length;

  return (
    <div className="pipeline-progress">
      <h2>
        Pipeline Progress
        <span className="step-count">
          {completedCount}/{steps.length}
        </span>
      </h2>
      <div className="progress-bar-container">
        <div
          className="progress-bar-fill"
          style={{ width: `${(completedCount / steps.length) * 100}%` }}
        />
      </div>
      <ul className="step-list">
        {steps.map((step) => (
          <li key={step.node} className={`step-item ${step.status}`}>
            {STATUS_ICON[step.status]}
            <div className="step-info">
              <span className="step-label">{step.label}</span>
              {step.status === "completed" && step.outputs && (
                <span className="step-meta">
                  {Object.entries(step.outputs)
                    .map(([k, v]) => `${k}: ${v}`)
                    .join(", ")}
                </span>
              )}
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}

