import type { InvoiceResult } from "../types";

interface Props {
  invoices: InvoiceResult[];
}

function confidenceColor(c: number): string {
  if (c >= 0.8) return "#10b981";
  if (c >= 0.5) return "#f59e0b";
  return "#ef4444";
}

function formatCurrency(n: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(n);
}

export function InvoiceTable({ invoices }: Props) {
  if (invoices.length === 0) return null;

  return (
    <div className="invoice-table-container">
      <h2>Processed Invoices ({invoices.length})</h2>
      <div className="table-scroll">
        <table className="invoice-table">
          <thead>
            <tr>
              <th>Vendor</th>
              <th>Date</th>
              <th>Invoice #</th>
              <th className="text-right">Total</th>
              <th>Category</th>
              <th className="text-center">Confidence</th>
            </tr>
          </thead>
          <tbody>
            {invoices.map((inv, i) => (
              <tr key={i}>
                <td className="vendor-cell">{inv.vendor}</td>
                <td>{inv.invoice_date}</td>
                <td>{inv.invoice_number || "—"}</td>
                <td className="text-right">{formatCurrency(inv.total)}</td>
                <td>
                  <span className="category-badge">{inv.category}</span>
                </td>
                <td className="text-center">
                  <span
                    className="confidence-dot"
                    style={{ backgroundColor: confidenceColor(inv.confidence) }}
                  />
                  {(inv.confidence * 100).toFixed(0)}%
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

