import { DollarSign, FileText, PieChart, AlertTriangle } from "lucide-react";
import type { FinalResult } from "../types";

interface Props {
  result: FinalResult;
}

function formatCurrency(n: number): string {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
  }).format(n);
}

const CATEGORY_COLORS = [
  "#3b82f6", "#10b981", "#f59e0b", "#ef4444",
  "#8b5cf6", "#ec4899", "#06b6d4", "#84cc16",
];

export function SummaryPanel({ result }: Props) {
  const maxSpend = Math.max(...result.by_category.map((c) => c.total));

  return (
    <div className="summary-panel">
      <h2>Run Summary</h2>

      <div className="summary-cards">
        <div className="summary-card">
          <div className="card-icon" style={{ backgroundColor: "#3b82f620", color: "#3b82f6" }}>
            <FileText size={20} />
          </div>
          <div className="card-content">
            <span className="card-value">{result.total_invoices}</span>
            <span className="card-label">Invoices</span>
          </div>
        </div>
        <div className="summary-card">
          <div className="card-icon" style={{ backgroundColor: "#10b98120", color: "#10b981" }}>
            <DollarSign size={20} />
          </div>
          <div className="card-content">
            <span className="card-value">{formatCurrency(result.total_spend)}</span>
            <span className="card-label">Total Spend</span>
          </div>
        </div>
        <div className="summary-card">
          <div className="card-icon" style={{ backgroundColor: "#8b5cf620", color: "#8b5cf6" }}>
            <PieChart size={20} />
          </div>
          <div className="card-content">
            <span className="card-value">{result.by_category.length}</span>
            <span className="card-label">Categories</span>
          </div>
        </div>
        {result.issues.length > 0 && (
          <div className="summary-card">
            <div className="card-icon" style={{ backgroundColor: "#f59e0b20", color: "#f59e0b" }}>
              <AlertTriangle size={20} />
            </div>
            <div className="card-content">
              <span className="card-value">{result.issues.length}</span>
              <span className="card-label">Issues</span>
            </div>
          </div>
        )}
      </div>

      <div className="category-breakdown">
        <h3>Spend by Category</h3>
        <div className="category-bars">
          {result.by_category
            .sort((a, b) => b.total - a.total)
            .map((cat, i) => (
              <div key={cat.category} className="category-bar-row">
                <div className="category-bar-label">
                  <span className="category-name">{cat.category}</span>
                  <span className="category-amount">
                    {formatCurrency(cat.total)} ({cat.count})
                  </span>
                </div>
                <div className="category-bar-track">
                  <div
                    className="category-bar-fill"
                    style={{
                      width: `${(cat.total / maxSpend) * 100}%`,
                      backgroundColor: CATEGORY_COLORS[i % CATEGORY_COLORS.length],
                    }}
                  />
                </div>
              </div>
            ))}
        </div>
      </div>

      {result.issues.length > 0 && (
        <div className="issues-section">
          <h3>Issues &amp; Assumptions</h3>
          <ul>
            {result.issues.map((issue, i) => (
              <li key={i}>{issue}</li>
            ))}
            {result.assumptions.map((a, i) => (
              <li key={`a-${i}`} className="assumption">{a}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

