  1→import { useCallback, useRef, useState } from "react";
  2→import { API_BASE_URL } from "../api/config";
  3→import type {
  4→  FinalResult,
  5→  InvoiceResult,
  6→  ProgressStep,
  7→  RunStatus,
  8→  SSEEvent,
  9→} from "../types";
 10→
 11→const PIPELINE_STEPS = [
 12→  { node: "load_images", label: "Loading invoice images" },
 13→  { node: "extract", label: "Extracting invoice fields (Vision LLM)" },
 14→  { node: "normalize", label: "Normalizing extracted data" },
 15→  { node: "categorize", label: "Categorizing invoices (LLM)" },
 16→  { node: "aggregate", label: "Aggregating totals" },
 17→  { node: "report", label: "Generating final report" },
 18→];
 19→
 20→function initialSteps(): ProgressStep[] {
 21→  return PIPELINE_STEPS.map((s) => ({ ...s, status: "pending" as const }));
 22→}
 23→
 24→export function useInvoiceRun() {
 25→  const [status, setStatus] = useState<RunStatus>("idle");
 26→  const [runId, setRunId] = useState<string | null>(null);
 27→  const [steps, setSteps] = useState<ProgressStep[]>(initialSteps());
 28→  const [invoices, setInvoices] = useState<InvoiceResult[]>([]);
 29→  const [finalResult, setFinalResult] = useState<FinalResult | null>(null);
 30→  const [error, setError] = useState<string | null>(null);
 31→  const [events, setEvents] = useState<SSEEvent[]>([]);
 32→  const abortRef = useRef<AbortController | null>(null);
 33→
 34→  const reset = useCallback(() => {
 35→    setStatus("idle");
 36→    setRunId(null);
 37→    setSteps(initialSteps());
 38→    setInvoices([]);
 39→    setFinalResult(null);
 40→    setError(null);
 41→    setEvents([]);
 42→  }, []);
 43→
 44→  const startRunWithFolder = useCallback(
 45→    async (folderPath: string, prompt?: string) => {
 46→      reset();
 47→      setStatus("connecting");
 48→
 49→      const abort = new AbortController();
 50→      abortRef.current = abort;
 51→
 52→      try {
 53→        const body: Record<string, string> = { folder_path: folderPath };
 54→        if (prompt) body.prompt = prompt;
 55→
 56→        const resp = await fetch(`${API_BASE_URL}/runs/stream`, {
 57→          method: "POST",
 58→          headers: { "Content-Type": "application/json" },
 59→          body: JSON.stringify(body),
 60→          signal: abort.signal,
 61→        });
 62→
 63→        if (!resp.ok) {
 64→          const err = await resp.json().catch(() => ({ error: resp.statusText }));
 65→          throw new Error(err.error || `HTTP ${resp.status}`);
 66→        }
 67→
 68→        processSSEStream(resp);
 69→      } catch (e: unknown) {
 70→        if ((e as Error).name === "AbortError") return;
 71→        setStatus("error");
 72→        setError((e as Error).message);
 73→      }
 74→    },
 75→    [reset]
 76→  );
 77→
 78→  const startRunWithFiles = useCallback(
 79→    async (files: File[], prompt?: string) => {
 80→      reset();
 81→      setStatus("connecting");
 82→
 83→      const abort = new AbortController();
 84→      abortRef.current = abort;
 85→
 86→      try {
 87→        const formData = new FormData();
 88→        files.forEach((f) => formData.append("files", f));
 89→        if (prompt) formData.append("prompt", prompt);
 90→
 91→        const resp = await fetch(`${API_BASE_URL}/runs/stream`, {
 92→          method: "POST",
 93→          body: formData,
 94→          signal: abort.signal,
 95→        });
 96→
 97→        if (!resp.ok) {
 98→          const err = await resp.json().catch(() => ({ error: resp.statusText }));
 99→          throw new Error(err.error || `HTTP ${resp.status}`);
100→        }
101→
102→        processSSEStream(resp);
103→      } catch (e: unknown) {
104→        if ((e as Error).name === "AbortError") return;
105→        setStatus("error");
106→        setError((e as Error).message);
107→      }
108→    },
109→    [reset]
110→  );
111→
112→  const cancel = useCallback(() => {
113→    abortRef.current?.abort();
114→    setStatus("idle");
115→  }, []);
116→
117→  function processSSEStream(resp: Response) {
118→    const reader = resp.body!.getReader();
119→    const decoder = new TextDecoder();
120→    let buffer = "";
121→
122→    setStatus("running");
123→
124→    function read(): void {
125→      reader.read().then(({ done, value }) => {
126→        if (done) {
127→          setStatus((prev) => (prev === "running" ? "completed" : prev));
128→          return;
129→        }
130→
131→        buffer += decoder.decode(value, { stream: true });
132→        const lines = buffer.split("\n");
133→        buffer = lines.pop() || "";
134→
135→        let currentEvent = "";
136→        let currentData = "";
137→
138→        for (const line of lines) {
139→          if (line.startsWith("event:")) {
140→            currentEvent = line.slice(6).trim();
141→          } else if (line.startsWith("data:")) {
142→            currentData = line.slice(5).trim();
143→          } else if (line === "" && currentEvent && currentData) {
144→            try {
145→              const parsed = JSON.parse(currentData);
146→              handleSSEEvent(currentEvent, parsed);
147→            } catch {
148→              // skip malformed
149→            }
150→            currentEvent = "";
151→            currentData = "";
152→          }
153→        }
154→
155→        read();
156→      });
157→    }
158→
159→    read();
160→  }
161→
162→  function handleSSEEvent(eventType: string, data: Record<string, unknown>) {
163→    const sseEvent: SSEEvent = { event: eventType as SSEEvent["event"], data };
164→    setEvents((prev) => [...prev, sseEvent]);
165→
166→    switch (eventType) {
167→      case "run_started":
168→        setRunId(data.run_id as string);
169→        break;
170→
171→      case "tool_call": {
172→        const node = data.tool as string;
173→        setSteps((prev) =>
174→          prev.map((s) =>
175→            s.node === node
176→              ? { ...s, status: "running", inputs: data.inputs as Record<string, unknown> }
177→              : s
178→          )
179→        );
180→        break;
181→      }
182→
183→      case "tool_result": {
184→        const node = data.tool as string;
185→        setSteps((prev) =>
186→          prev.map((s) =>
187→            s.node === node
188→              ? { ...s, status: "completed", outputs: data.result as Record<string, unknown> }
189→              : s
190→          )
191→        );
192→        break;
193→      }
194→
195→      case "invoice_result":
196→        setInvoices((prev) => [...prev, data as unknown as InvoiceResult]);
197→        break;
198→
199→      case "final_result":
200→        setFinalResult(data as unknown as FinalResult);
201→        setStatus("completed");
202→        break;
203→
204→      case "error":
205→        setError(data.error as string);
206→        setStatus("error");
207→        break;
208→    }
209→  }
210→
211→  return {
212→    status,
213→    runId,
214→    steps,
215→    invoices,
216→    finalResult,
217→    error,
218→    events,
219→    startRunWithFolder,
220→    startRunWithFiles,
221→    cancel,
222→    reset,
223→  };
224→}
225→

