import { useCallback, useRef, useState } from "react";
import { API_BASE_URL } from "../api/config";
import type {
  FinalResult,
  InvoiceResult,
  ProgressStep,
  RunStatus,
  SSEEvent,
} from "../types";

const PIPELINE_STEPS = [
  { node: "load_images", label: "Loading invoice images" },
  { node: "extract", label: "Extracting invoice fields (Vision LLM)" },
  { node: "normalize", label: "Normalizing extracted data" },
  { node: "categorize", label: "Categorizing invoices (LLM)" },
  { node: "aggregate", label: "Aggregating totals" },
  { node: "report", label: "Generating final report" },
];

function initialSteps(): ProgressStep[] {
  return PIPELINE_STEPS.map((s) => ({ ...s, status: "pending" as const }));
}

export function useInvoiceRun() {
  const [status, setStatus] = useState<RunStatus>("idle");
  const [runId, setRunId] = useState<string | null>(null);
  const [steps, setSteps] = useState<ProgressStep[]>(initialSteps());
  const [invoices, setInvoices] = useState<InvoiceResult[]>([]);
  const [finalResult, setFinalResult] = useState<FinalResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [events, setEvents] = useState<SSEEvent[]>([]);
  const abortRef = useRef<AbortController | null>(null);

  const reset = useCallback(() => {
    setStatus("idle");
    setRunId(null);
    setSteps(initialSteps());
    setInvoices([]);
    setFinalResult(null);
    setError(null);
    setEvents([]);
  }, []);

  const startRunWithFolder = useCallback(
    async (folderPath: string, prompt?: string) => {
      reset();
      setStatus("connecting");

      const abort = new AbortController();
      abortRef.current = abort;

      try {
        const body: Record<string, string> = { folder_path: folderPath };
        if (prompt) body.prompt = prompt;

        const resp = await fetch(`${API_BASE_URL}/runs/stream`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(body),
          signal: abort.signal,
        });

        if (!resp.ok) {
          const err = await resp.json().catch(() => ({ error: resp.statusText }));
          throw new Error(err.error || `HTTP ${resp.status}`);
        }

        processSSEStream(resp);
      } catch (e: unknown) {
        if ((e as Error).name === "AbortError") return;
        setStatus("error");
        setError((e as Error).message);
      }
    },
    [reset]
  );

  const startRunWithFiles = useCallback(
    async (files: File[], prompt?: string) => {
      reset();
      setStatus("connecting");

      const abort = new AbortController();
      abortRef.current = abort;

      try {
        const formData = new FormData();
        files.forEach((f) => formData.append("files", f));
        if (prompt) formData.append("prompt", prompt);

        const resp = await fetch(`${API_BASE_URL}/runs/stream`, {
          method: "POST",
          body: formData,
          signal: abort.signal,
        });

        if (!resp.ok) {
          const err = await resp.json().catch(() => ({ error: resp.statusText }));
          throw new Error(err.error || `HTTP ${resp.status}`);
        }

        processSSEStream(resp);
      } catch (e: unknown) {
        if ((e as Error).name === "AbortError") return;
        setStatus("error");
        setError((e as Error).message);
      }
    },
    [reset]
  );

  const cancel = useCallback(() => {
    abortRef.current?.abort();
    setStatus("idle");
  }, []);

  function processSSEStream(resp: Response) {
    const reader = resp.body!.getReader();
    const decoder = new TextDecoder();
    let buffer = "";
    // Persist across chunks
    let currentEvent = "";
    let currentData = "";

    setStatus("running");

    function read(): void {
      reader.read().then(({ done, value }) => {
        if (done) {
          // Flush any remaining buffered event
          if (currentEvent && currentData) {
            dispatch(currentEvent, currentData);
          }
          setStatus((prev) => (prev === "running" ? "completed" : prev));
          return;
        }

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";

        for (const rawLine of lines) {
          const line = rawLine.replace(/\r$/, "");

          if (line.startsWith("event:")) {
            currentEvent = line.slice(6).trim();
          } else if (line.startsWith("data:")) {
            currentData = line.slice(5).trim();
          } else if (line === "") {
            // Blank line = end of SSE message
            if (currentEvent && currentData) {
              dispatch(currentEvent, currentData);
            }
            currentEvent = "";
            currentData = "";
          }
        }

        read();
      });
    }

    function dispatch(eventType: string, dataStr: string) {
      try {
        const parsed = JSON.parse(dataStr);
        handleSSEEvent(eventType, parsed);
      } catch {
        // skip malformed JSON
      }
    }

    read();
  }

  function handleSSEEvent(eventType: string, data: Record<string, unknown>) {
    const sseEvent: SSEEvent = { event: eventType as SSEEvent["event"], data };
    setEvents((prev) => [...prev, sseEvent]);

    switch (eventType) {
      case "run_started":
        setRunId(data.run_id as string);
        break;

      case "tool_call": {
        const node = data.tool as string;
        setSteps((prev) =>
          prev.map((s) =>
            s.node === node
              ? { ...s, status: "running", inputs: data.inputs as Record<string, unknown> }
              : s
          )
        );
        break;
      }

      case "tool_result": {
        const node = data.tool as string;
        setSteps((prev) =>
          prev.map((s) =>
            s.node === node
              ? { ...s, status: "completed", outputs: data.outputs as Record<string, unknown> }
              : s
          )
        );
        break;
      }

      case "invoice_result": {
        const invoice = data.invoice as Record<string, unknown>;
        if (invoice) {
          setInvoices((prev) => [...prev, invoice as unknown as InvoiceResult]);
        }
        break;
      }

      case "final_result": {
        const result = data.result as Record<string, unknown>;
        if (result) {
          setFinalResult(result as unknown as FinalResult);
        }
        setStatus("completed");
        break;
      }

      case "error":
        setError(data.error as string);
        setStatus("error");
        break;
    }
  }

  return {
    status,
    runId,
    steps,
    invoices,
    finalResult,
    error,
    events,
    startRunWithFolder,
    startRunWithFiles,
    cancel,
    reset,
  };
}

